let total = items.len();
let current = RwSignal::new(0usize);
let score = RwSignal::new(0usize);
let answered = RwSignal::new(false);
let selected = RwSignal::new(Option::<usize>::None);
let shuffled: Vec<(Vec<String>, usize)> = items
    .iter()
    .map(|item| {
        let all = std::iter::once(item.correct.clone())
            .chain(item.distractors.iter().cloned())
            .collect::<Vec<_>>();
        shuffle_answers(all)
    })
    .collect();
let shuffled = StoredValue::new_local(shuffled);
let items = StoredValue::new_local(items);
let on_answer = move |idx: usize| {
    if answered.get() {
        return;
    }
    answered.set(true);
    selected.set(Some(idx));
    let q = current.get();
    let (_, correct_idx) = shuffled.with_value(|s| (s[q].0.clone(), s[q].1));
    if idx == correct_idx {
        score.update(|s| *s += 1);
    }
};
let on_next = move |_| {
    current.update(|c| *c += 1);
    answered.set(false);
    selected.set(None);
};
view! {
    < ScoreBoard score = score.into() total = total current = current.into() /> {
    move || { let q = current.get(); if q >= total { view! { < div > < h2 >
    "Quiz complete!" </ h2 > < p > "Final score: " { score.get() } " / " { total } </
    p > </ div > } .into_any() } else { let code = items.with_value(| it | it[q].code
    .clone()); let (answers, correct_idx) = shuffled.with_value(| s | s[q].clone());
    view! { < div class = "fluid-container" style = "text-align: right" > { move || {
    if answered.get() && current.get() + 1 < total { view! { < button on : click =
    on_next > "Next" </ button > } .into_any() } else { view! { < span ></ span > }
    .into_any() } } } </ div > < QuizCard code = code answers = answers correct_idx =
